dark.customCSS:
/* --- VINTAGE CRT TERMINAL OVERHAUL --- */
@keyframes flicker {
  0% { opacity: 0.97611; }
  5% { opacity: 0.98221; }
  10% { opacity: 0.99444; }
  15% { opacity: 0.98444; }
  20% { opacity: 0.99444; }
  25% { opacity: 0.97444; }
  100% { opacity: 0.99; }
}

body {
	background-color: #050400 !important;
	font-family: 'JetBrains Mono', 'Courier New', monospace !important;
	animation: flicker 0.15s infinite;
}

/* Scanline Overlay */
body::before {
	content: ' ';
	display: block;
	position: fixed;
	top: 0; left: 0; bottom: 0; right: 0;
	background: linear-gradient(rgba(18, 16, 0, 0) 50%, rgba(0, 0, 0, 0.25) 50%), linear-gradient(90deg, rgba(255, 0, 0, 0.06), rgba(0, 255, 0, 0.02), rgba(0, 0, 255, 0.06));
	z-index: 9999;
	pointer-events: none;
	background-size: 100% 4px, 3px 100%;
}

/* Phosphor Text Glow */
.prose, .prose h1, .prose h2, .prose p, span, label {
	color: #ffb000 !important;
	text-shadow: 0 0 8px rgba(255, 176, 0, 0.6) !important;
}

/* Blocky Terminal UI */
input, textarea, .bg-gray-850, .bg-gray-900 {
	background-color: #0a0800 !important;
	border: 2px solid #ffb000 !important;
	border-radius: 0px !important;
	color: #ffb000 !important;
	box-shadow: 0 0 10px rgba(255, 176, 0, 0.2);
}

/* Hard-Edge Buttons */
button.bg-blue-500, button.bg-blue-600, .btn-primary {
	background-color: #ffb000 !important;
	color: #000 !important;
	border-radius: 0px !important;
	font-weight: 900 !important;
	text-transform: uppercase;
	border: none !important;
	box-shadow: 4px 4px 0px #664400 !important;
}

button:active {
	transform: translate(2px, 2px);
	box-shadow: 0px 0px 0px !important;
}

/* Hide unnecessary rounded shadows */
* {
	box-shadow: none !important;
	border-radius: 0px !important;
}

dark.canvasScript:
/**
 * Title: Geometric Mainframe
 * Description: Rotating amber wireframe polygons that drift like data fragments.
 */

const CONFIG = {
    shardCount: 15,
    color: 'rgba(255, 176, 0, 0.2)',
    rotationSpeed: 0.005,
    driftSpeed: 0.3
};

let canvas, ctx, w, h;
let shards = [];

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    shards = [];
    for (let i = 0; i < CONFIG.shardCount; i++) {
        shards.push({
            x: Math.random() * w,
            y: Math.random() * h,
            size: Math.random() * 80 + 40,
            angle: Math.random() * Math.PI * 2,
            rot: (Math.random() - 0.5) * 0.02,
            vx: (Math.random() - 0.5) * CONFIG.driftSpeed,
            vy: (Math.random() - 0.5) * CONFIG.driftSpeed,
            sides: Math.floor(Math.random() * 3) + 3 // 3 to 5 sides
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    ctx.strokeStyle = CONFIG.color;
    ctx.lineWidth = 1;

    for (let s of shards) {
        s.x += s.vx; s.y += s.vy;
        s.angle += s.rot;

        if (s.x < -100) s.x = w + 100; if (s.x > w + 100) s.x = -100;
        if (s.y < -100) s.y = h + 100; if (s.y > h + 100) s.y = -100;

        ctx.beginPath();
        for (let i = 0; i < s.sides; i++) {
            let x = s.x + Math.cos(s.angle + (i * Math.PI * 2) / s.sides) * s.size;
            let y = s.y + Math.sin(s.angle + (i * Math.PI * 2) / s.sides) * s.size;
            if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
        }
        ctx.closePath();
        ctx.stroke();
    }
    requestAnimationFrame(render);
}

